package com.zorvyn.financebackend.security;import com.zorvyn.financebackend.model.AppUser;public final class RequestContext {    private static final ThreadLocal<AppUser> CURRENT_USER = new ThreadLocal<>();    private RequestContext() {    }    public static AppUser getCurrentUser() {        return CURRENT_USER.get();    }    public static void setCurrentUser(AppUser user) {        CURRENT_USER.set(user);    }    public static void clear() {        CURRENT_USER.remove();    }}